    'programs.detail3_intro': 'The programme trains highly qualified scientific and academic staff capable of generating new knowledge, solving complex problems, and conducting independent research in the field of food technologies.',
    'programs.detail3_focus': 'Research focuses on improving food quality and safety, scientific substantiation of technological foundations, resource and energy efficiency, enhancement of nutritional and biological value, and innovative development of food technology theory and practice.',
    'programs.detail3_structure': 'Studies include language, general scientific and professional training cycles, as well as elective disciplines for in-depth study of the chosen field. Doctoral candidates can conduct research at scientific institutes and universities in Europe (Germany, Switzerland, France, Slovakia, Poland).',
    'programs.detail3_careers': '<strong>Possible positions:</strong> research fellow, university lecturer, enterprise director, laboratory manager.',
    'science.tag': 'Science and research',
    'science.title': 'At the forefront of <em>food science</em>',
    'science.desc': 'The department\'s research focuses on creating innovative, resource- and energy-efficient technologies for fermentation and winemaking products — from spirit and yeast to beer, kvass, kombucha and wine. The team continues the traditions of scientific schools in malting, brewing, spirit rectification and winemaking, annually obtaining Ukrainian patents, publishing dozens of papers in professional and international journals, and involving students in real research projects.',
    'science.card1Title': 'Microbial synthesis and bioengineering',
    'science.card1Text': 'Research into high-efficiency microbial synthesis technologies for new fermented products. Development of innovative microorganism strains for the food industry.',
    'science.card2Title': 'Nanotechnology for food safety',
    'science.card2Text': 'Application of nanotechnology to ensure the safety and quality of fermentation and winemaking products.',
    'science.card3Title': 'Energy-saving technologies',
    'science.card3Text': 'Development of resource- and energy-saving production technologies for greening industrial processes.',
    'science.card4Title': 'Functional fermented products',
    'science.card4Text': 'Creation of new functional beverages based on fermentation — kombucha, probiotic drinks, non-alcoholic beer.',
    'science.pubPublications': 'Scientific publications',
    'science.pubPatents': 'Patents',
    'science.pubConferences': 'Scientific conferences',
    'science.pubProjects': 'International projects',
    'science.defenseTitle': 'Successful PhD defence',
    'science.defenseP1': 'Department graduate <strong>Olha Uspalenko</strong> defended her dissertation «Improvement of technology of non-alcoholic wines» under the supervision of Professor Maryna Bilko.',
    'science.defenseP2': 'The research focuses on selecting optimal grape varieties and enological practices to obtain non-alcoholic wines with vivid aroma, harmonious taste and stable quality. The developed technologies were tested in production and received high praise from industry experts.',
    'science.defenseP3': 'The ad hoc specialised academic council unanimously awarded Olha the degree of <strong>Doctor of Philosophy</strong> in speciality 181 «Food Technologies».',
    'science.defenseNote': 'We sincerely congratulate Olha and her supervisor! We wish you new discoveries and bold advances in innovative winemaking in Ukraine!',
    'science.defenseAlt1': 'Olha Uspalenko dissertation defence',
    'science.defenseAlt2': 'Dissertation defence — specialised academic council',
