    'programs.detail2_e2': 'Fondements théoriques des systèmes logistiques dans la production de fermentation',
    'programs.detail2_e3': 'Organisation des systèmes logistiques et de surveillance dans la production de fermentation et de vinification',
    'programs.detail2_e4': 'Processus biotechnologiques dans les technologies de fermentation et de vinification',
    'programs.detail2_e5': 'Fondements théoriques des processus biotechnologiques dans l\'industrie',
    'programs.detail2_e6': 'Fondements biotechnologiques de l\'industrie de la fermentation',
